import React, { useCallback, useEffect, useState } from 'react';
import { Pressable, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useFocusEffect } from '@react-navigation/native';
import AppIcon from '../components/AppIcon';
import CustomerBottomNav from '../components/CustomerBottomNav';
import ScreenHeader from '../components/ScreenHeader';
import { createShadow } from '../styles/shadows';
import { theme } from '../styles/theme';

const CustomerSubscriptionScreen = () => {
  const [showForm, setShowForm] = useState(false);
  const [qty, setQty] = useState(0);
  const [qtyText, setQtyText] = useState('0');
  const [frequency, setFrequency] = useState<'Daily' | 'Weekly' | 'Monthly'>('Daily');
  const [time, setTime] = useState<'Morning' | 'Afternoon' | 'Evening'>('Morning');
  const [activeSubscription, setActiveSubscription] = useState<{
    qty: number;
    frequency: 'Daily' | 'Weekly' | 'Monthly';
    time: 'Morning' | 'Afternoon' | 'Evening';
  } | null>(null);
  const [loaded, setLoaded] = useState(false);
  const storageKey = 'customerSubscription';

  const loadSubscription = useCallback(async () => {
    try {
      const saved = await AsyncStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed?.qty && parsed?.frequency && parsed?.time) {
          setActiveSubscription(parsed);
        } else {
          setActiveSubscription(null);
        }
      } else {
        setActiveSubscription(null);
      }
    } catch {
      setActiveSubscription(null);
    } finally {
      setLoaded(true);
    }
  }, []);

  useEffect(() => {
    loadSubscription();
  }, [loadSubscription]);

  useFocusEffect(
    useCallback(() => {
      loadSubscription();
    }, [loadSubscription])
  );

  const handleSave = async () => {
    const payload = { qty, frequency, time };
    await AsyncStorage.setItem(storageKey, JSON.stringify(payload));
    setActiveSubscription(payload);
    setShowForm(false);
  };

  const syncQty = (value: number) => {
    const next = Math.max(0, value);
    setQty(next);
    setQtyText(String(next));
  };

  const handleQtyChange = (value: string) => {
    const digitsOnly = value.replace(/[^0-9]/g, '');
    setQtyText(digitsOnly);
    if (!digitsOnly) {
      return;
    }
    const parsed = parseInt(digitsOnly, 10);
    if (Number.isFinite(parsed)) {
      setQty(Math.max(0, parsed));
    }
  };

  const handleQtyBlur = () => {
    if (!qtyText.trim()) {
      syncQty(0);
      return;
    }
    const parsed = parseInt(qtyText, 10);
    if (!Number.isFinite(parsed) || parsed < 0) {
      syncQty(0);
      return;
    }
    syncQty(parsed);
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <ScreenHeader
          title="Subscription"
          subtitle="A clean recurring-delivery screen with one view for plan details, schedule, and editing."
        />

        {loaded && !activeSubscription && !showForm ? (
          <View style={styles.emptyState}>
            <View style={styles.emptyIcon}>
              <AppIcon name="calendar-clear-outline" size={28} color={theme.colors.primary} />
            </View>
            <Text style={styles.emptyTitle}>No subscription yet</Text>
            <Text style={styles.emptyText}>Create a recurring plan so deliveries happen automatically without repeating the full order flow.</Text>
            <Pressable style={styles.primaryButton} onPress={() => setShowForm(true)}>
              <AppIcon name="add-circle-outline" size={18} color="#fff" />
              <Text style={styles.primaryButtonText}>Create subscription</Text>
            </Pressable>
          </View>
        ) : null}

        {showForm ? (
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Plan details</Text>
            <Text style={styles.cardSubtitle}>Choose how many cans arrive and when they should come.</Text>

            <Text style={styles.label}>Quantity</Text>
            <View style={styles.qtyShell}>
              <AppIcon name="cube-outline" size={18} color={theme.colors.textTertiary} />
              <TextInput
                style={styles.qtyInput}
                value={qtyText}
                onChangeText={handleQtyChange}
                onBlur={handleQtyBlur}
                keyboardType="number-pad"
                returnKeyType="done"
                selectTextOnFocus
                maxLength={3}
                placeholder="0"
                placeholderTextColor={theme.colors.textTertiary}
              />
            </View>

            <Text style={styles.label}>Frequency</Text>
            <View style={styles.chipRow}>
              {(['Daily', 'Weekly', 'Monthly'] as const).map((option) => (
                <Pressable
                  key={option}
                  style={[styles.choiceChip, frequency === option && styles.choiceChipActive]}
                  onPress={() => setFrequency(option)}
                >
                  <Text style={[styles.choiceText, frequency === option && styles.choiceTextActive]}>{option}</Text>
                </Pressable>
              ))}
            </View>

            <Text style={styles.label}>Preferred time</Text>
            <View style={styles.chipRow}>
              {(['Morning', 'Afternoon', 'Evening'] as const).map((option) => (
                <Pressable
                  key={option}
                  style={[styles.choiceChip, time === option && styles.choiceChipActive]}
                  onPress={() => setTime(option)}
                >
                  <Text style={[styles.choiceText, time === option && styles.choiceTextActive]}>{option}</Text>
                </Pressable>
              ))}
            </View>

            <Pressable style={styles.primaryButton} onPress={handleSave}>
              <AppIcon name="checkmark-circle-outline" size={18} color="#fff" />
              <Text style={styles.primaryButtonText}>Save subscription</Text>
            </Pressable>
          </View>
        ) : null}

        {activeSubscription && !showForm ? (
          <View style={styles.card}>
            <View style={styles.cardTitleRow}>
              <Text style={styles.cardTitle}>Active plan</Text>
              <View style={styles.activeBadge}>
                <AppIcon name="checkmark-circle" size={14} color={theme.colors.secondary} />
                <Text style={styles.activeBadgeText}>Active</Text>
              </View>
            </View>
            <View style={styles.planRow}>
              <View style={styles.planTile}>
                <Text style={styles.tileLabel}>Quantity</Text>
                <Text style={styles.tileValue}>{activeSubscription.qty} cans</Text>
              </View>
              <View style={styles.planTile}>
                <Text style={styles.tileLabel}>Frequency</Text>
                <Text style={styles.tileValue}>{activeSubscription.frequency}</Text>
              </View>
              <View style={styles.planTile}>
                <Text style={styles.tileLabel}>Time</Text>
                <Text style={styles.tileValue}>{activeSubscription.time}</Text>
              </View>
            </View>
            <Pressable style={styles.secondaryButton} onPress={() => setShowForm(true)}>
              <AppIcon name="create-outline" size={18} color={theme.colors.primary} />
              <Text style={styles.secondaryButtonText}>Edit subscription</Text>
            </Pressable>
          </View>
        ) : null}
      </View>
      <CustomerBottomNav active="CustomerSubscription" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: theme.colors.background
  },
  content: {
    flex: 1,
    padding: 18,
    paddingBottom: 110
  },
  emptyState: {
    marginTop: 6,
    borderRadius: 30,
    padding: 24,
    backgroundColor: theme.colors.surface,
    borderWidth: 1,
    borderColor: theme.colors.stroke,
    alignItems: 'center',
    ...createShadow({ color: '#163456', opacity: 0.1, radius: 18, elevation: 6 })
  },
  emptyIcon: {
    width: 58,
    height: 58,
    borderRadius: 29,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: theme.colors.primarySoft
  },
  emptyTitle: {
    marginTop: 16,
    color: theme.colors.text,
    fontSize: 22,
    fontWeight: '800'
  },
  emptyText: {
    marginTop: 8,
    color: theme.colors.textSecondary,
    fontSize: 14,
    lineHeight: 22,
    textAlign: 'center'
  },
  card: {
    borderRadius: 30,
    padding: 20,
    backgroundColor: theme.colors.surface,
    borderWidth: 1,
    borderColor: theme.colors.stroke,
    ...createShadow({ color: '#163456', opacity: 0.1, radius: 18, elevation: 6 })
  },
  cardTitleRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  cardTitle: {
    color: theme.colors.text,
    fontSize: 22,
    fontWeight: '800'
  },
  cardSubtitle: {
    marginTop: 8,
    color: theme.colors.textSecondary,
    fontSize: 14,
    lineHeight: 22
  },
  label: {
    marginTop: 16,
    marginBottom: 10,
    color: theme.colors.textSecondary,
    fontSize: 13,
    fontWeight: '800',
    textTransform: 'uppercase',
    letterSpacing: 0.7
  },
  qtyShell: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 10,
    borderRadius: 20,
    paddingHorizontal: 14,
    backgroundColor: theme.colors.surfaceMuted,
    borderWidth: 1,
    borderColor: theme.colors.stroke
  },
  qtyInput: {
    flex: 1,
    paddingVertical: 15,
    color: theme.colors.text,
    fontSize: 18,
    fontWeight: '700'
  },
  chipRow: {
    flexDirection: 'row',
    gap: 10,
    flexWrap: 'wrap'
  },
  choiceChip: {
